import { useState } from "react";

function generateRoast() {
  const lines = [
    "Bhavika, your decisions are… bold 😭",
    "You age like WiFi… unpredictable 📶",
    "Honestly, chaos follows you 😂",
    "Still iconic though 😌"
  ];
  return lines[Math.floor(Math.random() * lines.length)];
}

export default function RoastBox() {
  const [text, setText] = useState(generateRoast());

  return (
    <div>
      <p>{text}</p>
      <button onClick={() => setText(generateRoast())}>Roast Again 🔥</button>
    </div>
  );
}
